/**
 * Get the saju month (1-12) for a given UTC date.
 * Returns { sajuMonth, sajuYear } where sajuYear accounts for
 * the fact that 小寒(month 12) and 大雪(month 11) in Dec/Jan
 * belong to the CURRENT year's cycle, and 立春 starts the NEW year.
 */
export function getSajuMonthFromDate(year: number, month0: number, day: number, hour: number = 12, minute: number = 0): { sajuMonth: number; sajuYear: number } {
  const targetMs = Date.UTC(year, month0, day, hour, minute);
  
  // Find all terms for this year and adjacent years
  const candidateTerms = SOLAR_TERM_DATA.filter(([y]) => y >= year - 1 && y <= year + 1);
  
  // Convert to timestamps and sort
  const termDates = candidateTerms.map(([y, sm, m, d, h, mi]) => ({
    timestamp: Date.UTC(y, m, d, h, mi),
    sajuMonth: sm,
    year: y,
  })).sort((a, b) => a.timestamp - b.timestamp);
  
  // Find which interval the target falls in
  let sajuMonth = 12; // default: before 立春 = 丑月
  let sajuYear = year - 1; // before 立春 = previous year
  
  for (let i = termDates.length - 1; i >= 0; i--) {
    if (targetMs >= termDates[i].timestamp) {
      sajuMonth = termDates[i].sajuMonth;
      // sajuYear: 立春(1) starts new year; months 11,12 in prev calendar year still belong to that year's stem
      sajuYear = termDates[i].year;
      // But for months 11 (大雪, ~Dec) and 12 (小寒, ~Jan), the saju year is complex:
      // 小寒 in Jan of year Y belongs to year Y-1's cycle (before 立春)
      // Actually: the year pillar changes at 立春, so we just use the term's year
      // and let the caller handle year pillar separately via getLichunDate()
      break;
    }
  }
  
  return { sajuMonth, sajuYear };
}

/**
 * Get the 立春 (Lichun) date for a given year.
 * Used to determine year pillar boundary.
 */
export function getLichunTimestamp(year: number): number {
  const lichun = SOLAR_TERM_DATA.find(([y, sm]) => y === year && sm === 1);
  if (!lichun) return Date.UTC(year, 1, 4); // fallback: Feb 4
  const [, , m, d, h, mi] = lichun;
  return Date.UTC(year, m, d, h, mi);
}